window.ETS_LC5 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["She's pushing a large container down a hallway.", "She's looking at information on a laptop screen.", "She's sorting through paper files.", "She's placing a hat on top of a file cabinet."], "optko": ["여자가 복도를 따라 대형 용기를 밀고 있다.", "여자가 노트북 화면에 있는 정보를 보고 있다.", "여자가 종이 파일들을 살펴보고 있다.", "여자가 파일 캐비닛 위에 모자를 놓고 있다."], "ans": 2, "audio": "Test_05-01.mp3", "img": "ets_t5_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["A worker is painting lines on the floor.", "A worker is using a machine to move some boxes.", "A worker is sealing some packages.", "A worker is repairing a motor."], "optko": ["작업자가 바닥에 선을 그리고 있다.", "작업자가 기계를 이용해 상자들을 옮기고 있다.", "작업자가 포장물을 밀봉하고 있다.", "작업자가 모터를 수리하고 있다."], "ans": 1, "audio": "Test_05-02.mp3", "img": "ets_t5_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["There are beverages available inside a tent.", "There are some people riding in an automobile.", "The man is reaching for a water bottle.", "The woman is moving some furniture."], "optko": ["텐트 안에 이용 가능한 음료들이 있다.", "자동차에 타 있는 사람들이 있다.", "남자가 물병을 향해 손을 뻗고 있다.", "여자가 가구를 옮기고 있다."], "ans": 0, "audio": "Test_05-03.mp3", "img": "ets_t5_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["The door of a clothing store has been propped open.", "Customers are waiting to enter a clothing store.", "One of the customers is trying on a jacket.", "Clothing is displayed outside on racks."], "optko": ["옷 가게의 문이 밑부분을 받쳐 열려 있다.", "고객들이 옷 가게에 들어가기 위해 기다리고 있다.", "고객들 중 한 명이 재킷을 입어 보고 있다.", "옷이 외부에 있는 거치대에 진열되어 있다."], "ans": 3, "audio": "Test_05-04.mp3", "img": "ets_t5_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["One of the men is lowering some window shades.", "One of the men is writing on a poster board.", "One of the women is putting on a sweater.", "One of the women is reading from a notebook."], "optko": ["남자들 중 한 명이 창문 블라인드를 내리고 있다.", "남자들 중 한 명이 포스터 보드에 뭔가 쓰고 있다.", "여자들 중 한 명이 스웨터를 입고 있는 중이다.", "여자들 중 한 명이 노트에 쓰여 있는 것을 읽고 있다."], "ans": 1, "audio": "Test_05-05.mp3", "img": "ets_t5_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["One of the cars is stopped at a stop sign.", "Some tires are stacked against a building.", "Some vehicles are being washed.", "A motorcycle is going through a gate."], "optko": ["자동차들 중 한 대가 정지 표지판 앞에 서 있다.", "타이어들이 건물 옆에 쌓여 있다.", "차량들이 세차되고 있다.", "오토바이가 문을 통과해 지나가고 있다."], "ans": 1, "audio": "Test_05-06.mp3", "img": "ets_t5_q6.jpg"}, {"n": 7, "part": 2, "q": "Where did you put the invoice from Stanson Incorporated?", "qko": "스탠슨 주식회사에서 온 송장을 어디에 두셨나요?", "opts": ["No, not yet.", "On your desk.", "The post office is crowded today."], "optko": ["아니요, 아직이요.", "당신 책상 위에요.", "오늘 우체국이 붐벼요."], "ans": 1, "audio": "Test_05-07.mp3"}, {"n": 8, "part": 2, "q": "Is the inspector coming this afternoon or tomorrow morning?", "qko": "조사관은 오늘 오후에 오나요, 아니면 내일 오전에 오나요?", "opts": ["The exterior light isn't working.", "He'll be here tomorrow.", "I'll take the next right turn."], "optko": ["외부 조명이 작동하지 않아요.", "내일 오실 거예요.", "다음번에 우회전할 거예요."], "ans": 1, "audio": "Test_05-08.mp3"}, {"n": 9, "part": 2, "q": "What's the total cost to remodel the office lobby?", "qko": "사무실 로비를 리모델링하는 데 드는 총 비용은 얼마인가요?", "opts": ["The view from this window is great.", "Over 50,000 dollars.", "No, a sofa and table."], "optko": ["이 창문에서 보이는 경관이 아주 멋져요.", "5만 달러가 넘어요.", "아니요, 소파와 테이블이요."], "ans": 1, "audio": "Test_05-09.mp3"}, {"n": 10, "part": 2, "q": "Are you getting the same type of desk or a different one?", "qko": "같은 종류의 책상을 구입하시나요, 아니면 다른 것으로 하시나요?", "opts": ["It's conveniently located.", "I can pick it up for you.", "The same type."], "optko": ["편리한 곳에 위치해 있어요.", "제가 갖다드릴 수 있어요.", "같은 종류요."], "ans": 2, "audio": "Test_05-10.mp3"}, {"n": 11, "part": 2, "q": "We're taking the clients to the theater this evening.", "qko": "우리가 오늘 저녁에 고객들을 극장에 데려갈 거예요.", "opts": ["He already ate.", "I'll reserve a taxi.", "From Australia."], "optko": ["그는 이미 식사했어요.", "제가 택시를 예약할게요.", "호주에서요."], "ans": 1, "audio": "Test_05-11.mp3"}, {"n": 12, "part": 2, "q": "When is your budget report due?", "qko": "예산 보고서 제출 기한이 언제인가요?", "opts": ["It was too expensive.", "I don't need one.", "By Tuesday at the latest."], "optko": ["그건 너무 비쌌어요.", "저는 필요 없어요.", "늦어도 화요일까지요."], "ans": 2, "audio": "Test_05-12.mp3"}, {"n": 13, "part": 2, "q": "Who can I talk to about getting a membership at this fitness center?", "qko": "여기 피트니스 센터의 회원 가입에 대해 누구와 상담할 수 있나요?", "opts": ["A monthly bill.", "Some new workout equipment.", "I can help you with that."], "optko": ["월간 고지서요.", "새 운동 장비요.", "제가 도와드릴 수 있어요."], "ans": 2, "audio": "Test_05-13.mp3"}, {"n": 14, "part": 2, "q": "Are you planning to buy a house in the city?", "qko": "도시에 있는 집을 구입할 계획이신가요?", "opts": ["A housecleaning company.", "I don't want to move.", "I'll be waiting at the post office."], "optko": ["주택 청소 회사요.", "저는 이사하고 싶지 않아요.", "우체국에서 기다리고 있을게요."], "ans": 1, "audio": "Test_05-14.mp3"}, {"n": 15, "part": 2, "q": "How did you decide on a venue for the fund-raising event?", "qko": "기금 마련 행사 장소는 어떻게 결정하셨나요?", "opts": ["A small contribution.", "I got a recommendation from a friend.", "To buy books for the library."], "optko": ["소액 기부금이요.", "친구에게 추천을 받았어요.", "도서관에 필요한 책들을 구입하기 위해서요."], "ans": 1, "audio": "Test_05-15.mp3"}, {"n": 16, "part": 2, "q": "Could you help Ms. Ishida update the expense reports?", "qko": "이시다 씨가 지출 보고서를 업데이트하는 것을 도와주시겠어요?", "opts": ["It's an electric vehicle.", "This restaurant is expensive.", "I'll have time after my meeting."], "optko": ["그건 전기 자동차예요.", "이 레스토랑은 비싸요.", "회의 후에 시간이 있을 거예요."], "ans": 2, "audio": "Test_05-16.mp3"}, {"n": 17, "part": 2, "q": "The sales representatives really appreciated the training we led.", "qko": "영업 직원들이 우리가 진행한 교육에 대해 정말로 감사해했어요.", "opts": ["The new transportation center nearby.", "No, but there is a manual online.", "Yes, they seemed to find it helpful."], "optko": ["근처에 있는 새 교통 센터요.", "아니요, 하지만 온라인에 설명서가 있습니다.", "네, 그분들이 도움이 된다고 생각한 것 같았어요."], "ans": 2, "audio": "Test_05-17.mp3"}, {"n": 18, "part": 2, "q": "Do you know who was promoted to senior director?", "qko": "누가 선임 이사로 승진되었는지 아세요?", "opts": ["It hasn't been announced yet.", "I received my promotional gift yesterday.", "I've seen that film."], "optko": ["아직 발표되지 않았어요.", "어제 홍보용 선물을 받았어요.", "그 영화 봤어요."], "ans": 0, "audio": "Test_05-18.mp3"}, {"n": 19, "part": 2, "q": "Isn't the registration deadline tomorrow?", "qko": "등록 마감일은 내일 아닌가요?", "opts": ["Here's a map that you can use.", "No, it's next week.", "My office is on the ninth floor."], "optko": ["여기 이용하실 수 있는 안내도입니다.", "아니요, 다음 주예요.", "제 사무실은 9층에 있어요."], "ans": 1, "audio": "Test_05-19.mp3"}, {"n": 20, "part": 2, "q": "Would you like some help installing that new software?", "qko": "새 소프트웨어를 설치하는 데 도움이 필요하신가요?", "opts": ["No, I'm sure we sent it out yesterday.", "Thanks, but I know how to do it.", "He can type very fast."], "optko": ["아니요, 우리가 어제 발송한 게 확실해요.", "감사하지만, 어떻게 하는지 알아요.", "그는 아주 빨리 타자를 칠 수 있어요."], "ans": 1, "audio": "Test_05-20.mp3"}, {"n": 21, "part": 2, "q": "Our factory makes the best cookies in the city.", "qko": "우리 공장이 이 도시에서 가장 맛있는 쿠키를 만듭니다.", "opts": ["A cup of sugar.", "He worked an afternoon shift.", "Aren't they delicious?"], "optko": ["설탕 한 컵이요.", "그는 오후 교대 근무를 했어요.", "정말 맛있지 않아요?"], "ans": 2, "audio": "Test_05-21.mp3"}, {"n": 22, "part": 2, "q": "The fruit market is still selling mangoes, isn't it?", "qko": "과일 시장에서 아직 망고를 팔고 있죠, 그렇지 않나요?", "opts": ["No thanks—I don't need anything.", "There's a waiting area in the lobby.", "Yes, I bought some there yesterday."], "optko": ["괜찮습니다. 아무것도 필요하지 않아요.", "로비에 대기 구역이 있어요.", "네, 어제 거기서 몇 개 샀어요."], "ans": 2, "audio": "Test_05-22.mp3"}, {"n": 23, "part": 2, "q": "Why are you staying in the office for lunch?", "qko": "점심시간에 왜 사무실에 남아 있나요?", "opts": ["No, they weren't.", "Just a salad and soup, please.", "Because it is raining."], "optko": ["아니요, 그렇지 않았어요.", "샐러드와 수프만 주세요.", "비가 내리고 있어서요."], "ans": 2, "audio": "Test_05-23.mp3"}, {"n": 24, "part": 2, "q": "How did the company basketball team play last night?", "qko": "어젯밤 회사 농구팀의 경기는 어땠나요?", "opts": ["Sure, I'll have a few.", "How can I sign up?", "The game was canceled."], "optko": ["물론이죠, 몇 개 먹을게요.", "어떻게 신청할 수 있죠?", "그 경기는 취소되었어요."], "ans": 2, "audio": "Test_05-24.mp3"}, {"n": 25, "part": 2, "q": "Isn't our department's quarterly report supposed to be sent out today?", "qko": "우리 부서의 분기 보고서가 오늘 발송되어야 하지 않나요?", "opts": ["No, he drinks coffee.", "There's a lot of information to include.", "Some office supplies."], "optko": ["아니요, 그는 커피를 마셔요.", "포함해야 할 정보가 많아요.", "사무용품이요."], "ans": 1, "audio": "Test_05-25.mp3"}, {"n": 26, "part": 2, "q": "Would you like a copy of the article I mentioned?", "qko": "제가 언급했던 기사의 사본을 드릴까요?", "opts": ["No, I'm not.", "Yes, I'd appreciate that.", "A Thursday morning appointment."], "optko": ["아니요, 저는 그렇지 않아요.", "네, 그렇게 해 주시면 감사하겠습니다.", "목요일 오전 예약이요."], "ans": 1, "audio": "Test_05-26.mp3"}, {"n": 27, "part": 2, "q": "Did you decide on the design for the new logo?", "qko": "새 로고 디자인은 결정했나요?", "opts": ["There are so many good options.", "Please adjust that sign by the door.", "Maybe he'll arrive today."], "optko": ["좋은 선택지가 너무 많아요.", "문 옆에 있는 간판을 조정해 주세요.", "그는 아마 오늘 도착할 거예요."], "ans": 0, "audio": "Test_05-27.mp3"}, {"n": 28, "part": 2, "q": "Our bookstore is having a sale today, isn't it?", "qko": "우리 서점이 오늘 세일을 하죠, 그렇지 않나요?", "opts": ["Sure, you can use my printer.", "I really enjoyed that book.", "It's only a small discount."], "optko": ["물론이죠, 제 프린터를 이용하셔도 돼요.", "그 책을 정말 재미있게 읽었어요.", "약간 할인할 뿐이에요."], "ans": 2, "audio": "Test_05-28.mp3"}, {"n": 29, "part": 2, "q": "Why haven't the painters arrived yet?", "qko": "페인트 작업자들이 왜 아직 도착하지 않았나요?", "opts": ["The keys are in the desk drawer.", "No, that's all right.", "I heard that traffic is heavy this morning."], "optko": ["열쇠는 책상 서랍 안에 있어요.", "아니요, 괜찮습니다.", "오늘 아침에 교통 체증이 극심하다고 들었어요."], "ans": 2, "audio": "Test_05-29.mp3"}, {"n": 30, "part": 2, "q": "Should I bring some flowers or some food to the party?", "qko": "파티에 꽃을 좀 가져가야 할까요, 아니면 음식을 좀 가져가야 할까요?", "opts": ["He's right down the hall.", "Don't you live next to a florist's shop?", "A few more hours."], "optko": ["그는 복도 바로 저쪽에 있습니다.", "꽃집 옆에 살지 않나요?", "몇 시간 더요."], "ans": 1, "audio": "Test_05-30.mp3"}, {"n": 31, "part": 2, "q": "The meeting can wait until tomorrow.", "qko": "회의는 내일로 미뤄도 돼요.", "opts": ["I'll make sure the room is set up.", "Did you bring an umbrella?", "No, he wasn't."], "optko": ["제가 회의실을 준비해 둘게요.", "우산 가져오셨나요?", "아니요, 그는 그렇지 않았어요."], "ans": 0, "audio": "Test_05-31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test_05-32-34.mp3", "qs": [{"n": 32, "q": "What does the woman ask the man to do for her?", "opts": ["Greet a client in the lobby", "Present a product pitch", "Organize some binders", "Make some photocopies"], "ans": 3, "ko": "여자가 첫 대사에서 부탁을 들어줄 수 있는지(Could you do me a favor) 물은 후, 두 번째 대사에서 각 직원을 위해 당신의 시장 분석 보고서 복사본이 필요하다(I need copies of your market analysis report made for each representative)고 했으므로 정답은 (D)이다."}, {"n": 33, "q": "What does the man say about some equipment?", "opts": ["It is operating smoothly.", "It was purchased recently.", "It needs to be plugged in.", "It has not yet been updated."], "ans": 1, "ko": "여자가 세 번째 대사에서 복사기를 작동시킬 수 없었다(I couldn't get the copy machine to work)고 하자, 남자가 지난달에 구입했다(We bought it last month!)며 놀라움을 나타내고 있으므로 정답은 (B)이다."}, {"n": 34, "q": "Where is the man?", "opts": ["At the office", "At a train station", "At a store", "At a client's headquarters"], "ans": 1, "ko": "남자가 마지막 대사에서 방금 기차에서 내렸다(I just got off the train)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "W", "en": "Hello, Tariq. Could you do me a favor?", "ko": "안녕하세요, 타리크. 제 부탁 하나만 들어주시겠어요?"}, {"sp": "M", "en": "Sure—what is it?", "ko": "물론이죠, 뭔가요?"}, {"sp": "W", "en": "I'm meeting with the Gerhard Group at ten A.M. for the product pitch, and I need copies of your market analysis report made for each representative.", "ko": "제가 오전 10시에 제품 홍보용 발표 때문에 게르하드 그룹을 만나는데, 각 직원을 위해 당신의 시장 분석 보고서 복사본이 필요해요."}, {"sp": "M", "en": "Aren't you at the office right now?", "ko": "지금 사무실에 계시지 않나요?"}, {"sp": "W", "en": "Actually, I came in early today, but I couldn't get the copy machine to work.", "ko": "실은, 오늘 일찍 출근했는데, 복사기를 작동시킬 수 없었어요."}, {"sp": "M", "en": "Seriously? We bought it last month!", "ko": "정말요? 지난달에 구입했잖아요!"}, {"sp": "W", "en": "I'm afraid so.", "ko": "안타깝게도 그래요."}, {"sp": "M", "en": "I just got off the train. I'll stop at Business Express on McAllister Street and take care of it on my way to the office.", "ko": "제가 방금 기차에서 내렸어요. 사무실로 가는 길에 맥앨리스터 가에 있는 비즈니스 익스프레스에 들러서 처리할게요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Cn", "audio": "Test_05-35-37.mp3", "qs": [{"n": 35, "q": "Where does the woman most likely work?", "opts": ["At a furniture store", "At a moving company", "At a post office", "At an office supply store"], "ans": 1, "ko": "남자가 첫 대사에서 여자에게 6월에 새 사무실로 이전하는데 귀사의 서비스를 예약하고 싶다(We are relocating to a new office in June and would like to book your services)고 했으므로 정답은 (B)이다."}, {"n": 36, "q": "Why will a representative visit the man's company tomorrow?", "opts": ["To provide an estimate", "To sign a contract", "To give a presentation", "To place an order"], "ans": 0, "ko": "여자가 두 번째 대사에서 현재 위치로 가서 가구와 장비를 옮기는 데 드는 비용을 견적해야 할 것(we'll need to come to your current location and estimate the cost of moving your furniture and equipment)이라고 했고, 마지막 대사에서 직원이 2시에 갈 수 있다(Our representative can be there at two)고 했다. 따라서 비용 견적을 위해 방문할 것임을 알 수 있으므로 정답은 (A)이다."}, {"n": 37, "q": "What information will the man most likely provide next?", "opts": ["A company's operating hours", "An account number", "A street address", "A telephone number"], "ans": 2, "ko": "여자가 마지막 대사에서 위치만 알면 된다(I'll just need to know where you're located)고 했으므로 정답은 (C)이다."}], "script": [{"sp": "W", "en": "Delton Van Lines. How can I help you?", "ko": "델튼 밴 라인즈입니다. 무엇을 도와드릴까요?"}, {"sp": "M", "en": "Hello. I'm the office manager at Woodsom Insurance Company. We are relocating to a new office in June and would like to book your services.", "ko": "안녕하세요. 우드섬 보험회사의 사무실 관리자입니다. 6월에 새 사무실로 이전하는데, 귀사의 서비스를 예약하고 싶습니다."}, {"sp": "W", "en": "Certainly! But before we reserve a date for the move, we'll need to come to your current location and estimate the cost of moving your furniture and equipment.", "ko": "알겠습니다! 하지만 이사 날짜를 예약하기 전에, 현재 위치로 가서 가구와 장비를 옮기는 데 드는 비용을 견적해야 할 겁니다."}, {"sp": "M", "en": "We have a staff meeting tomorrow morning, so no one's available to show you around then. But tomorrow afternoon works.", "ko": "내일 오전에 직원회의가 있어서, 그때는 안내해 드릴 수 있는 사람이 없습니다. 하지만 내일 오후는 괜찮습니다."}, {"sp": "W", "en": "Perfect! Our representative can be there at two. I'll just need to know where you're located.", "ko": "아주 좋습니다! 저희 직원이 2시에 갈 수 있습니다. 위치만 알면 됩니다."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test_05-38-40.mp3", "qs": [{"n": 38, "q": "What department does the man work in?", "opts": ["Legal", "Accounting", "Human resources", "Public relations"], "ans": 2, "ko": "남자가 첫 대사에서 인사부에서 전화한다(I'm calling from the human resources department)고 했으므로 정답은 (C)이다."}, {"n": 39, "q": "What kind of work has the woman been hired to do?", "opts": ["Scientific research", "Book editing", "Office management", "Legal advising"], "ans": 0, "ko": "여자가 첫 대사에서 과학 연구팀에 합류할 예정(I'll be joining the scientific research team)이라고 했으므로 정답은 (A)이다."}, {"n": 40, "q": "What will the man send the woman this afternoon?", "opts": ["A password", "A travel reimbursement", "A security badge", "A contract"], "ans": 3, "ko": "남자가 마지막 대사에서 여자의 계약서에 대해 이야기하면서 오늘 오후에 보내겠다(Your contract ~ I can send it to you this afternoon)고 했으므로 정답은 (D)이다."}], "script": [{"sp": "M", "en": "Doctor MacMillan, I'm calling from the human resources department. I'm in charge of your onboarding, and I wanted to confirm your start date. It's the first of April, right?", "ko": "맥밀란 박사님, 인사부에서 전화를 드립니다. 제가 박사님의 신규 입사자 교육을 담당하고 있는데, 시작 날짜를 확인하고 싶어요. 4월 1일이 맞죠?"}, {"sp": "W", "en": "Right. That's when I'll be joining the scientific research team. And as you probably know, I'm still finishing up a research paper with my current institution.", "ko": "그렇습니다. 그때 제가 과학 연구팀에 합류할 예정입니다. 그리고 아마 아시겠지만, 제가 아직 현재 기관의 연구 논문을 마무리하고 있습니다."}, {"sp": "M", "en": "Yes, the director did tell me that. Your contract includes time for you to finish up your previous commitments. I can send it to you this afternoon.", "ko": "네, 소장님께서 말씀하셨습니다. 계약서에 이전 업무들을 마무리하기 위한 시간이 포함되어 있습니다. 그것을 오늘 오후에 보내 드릴게요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Cn / W-Am", "audio": "Test_05-41-43.mp3", "qs": [{"n": 41, "q": "What recently happened at the business?", "opts": ["Its monthly rent increased.", "It received many orders.", "It was featured in a magazine.", "It passed an inspection."], "ans": 1, "ko": "첫 번째 여자가 첫 대사에서 소속 회사가 최근 초콜릿 캔디의 온라인 주문을 많이 받고 있다(We've been getting a lot of online orders for our chocolate candies lately)고 했으므로 정답은 (B)이다."}, {"n": 42, "q": "According to the man, what will help the business?", "opts": ["Purchasing updated equipment", "Offering different products", "Extending store hours", "Hiring more employees"], "ans": 3, "ko": "남자가 첫 대사에서 오전에 근무할 사람을 몇 명 더 고용해야 할 것 같다며, 포장과 배송을 도와줄 수 있을 것(I think we should hire a few more people to work in the mornings. They could help with packaging and shipping)이라고 했으므로 정답은 (D)이다."}, {"n": 43, "q": "Who does Rebecca say she will call today?", "opts": ["A packaging designer", "An Internet service provider", "A delivery service", "A bank"], "ans": 2, "ko": "두 번째 여자(레베카)가 첫 대사에서 배송 서비스 업체가 하루에 두 번씩 배송품을 가져갈 수 있을지도 물어보는 게 좋겠다며, 오늘 전화하겠다(I also think that we should ask if our delivery service can pick up our packages twice a day ~ I'll call them today)고 했으므로 정답은 (C)이다."}], "script": [{"sp": "W1", "en": "We've been getting a lot of online orders for our chocolate candies lately. I'm glad to see the increase in orders, but I'm worried about meeting the demands. Are we going to be able to fill and ship all these orders?", "ko": "최근 초콜릿 캔디의 온라인 주문을 많이 받고 있습니다. 주문이 증가해서 기쁘지만 수요를 충족할 수 있을지 걱정입니다. 이 주문을 모두 처리하고 배송할 수 있을까요?"}, {"sp": "M", "en": "I think we should hire a few more people to work in the mornings. They could help with packaging and shipping. What do you think, Rebecca?", "ko": "오전에 근무할 사람을 몇 명 더 고용해야 할 것 같아요. 포장과 배송을 도와줄 수 있을 거예요. 어떻게 생각하세요, 레베카?"}, {"sp": "W2", "en": "I agree. I also think that we should ask if our delivery service can pick up our packages twice a day instead of just once a day—maybe every morning and afternoon. I'll call them today.", "ko": "동의합니다. 그리고 배송 서비스 업체가 하루에 단 한 번이 아니라 하루에 두 번씩, 아마 매일 아침과 오후에 배송품을 가져갈 수 있을지도 물어보는 게 좋겠어요. 제가 오늘 전화할게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test_05-44-46.mp3", "qs": [{"n": 44, "q": "What do the speakers manufacture?", "opts": ["Shoes", "Luggage", "Furniture", "Sports equipment"], "ans": 2, "ko": "여자가 첫 대사에서 지난 며칠 동안 10개의 소파 주문을 받은(~ the ten sofa orders that we've received the past few days) 것을 언급했으므로 정답은 (C)이다."}, {"n": 45, "q": "Who does the man suggest contacting?", "opts": ["A leather supplier", "A delivery driver", "An interior designer", "A machine technician"], "ans": 0, "ko": "남자가 첫 대사에서 지역 가죽 공급업체를 언급하며, 소파 10개를 만들 만큼 충분한 양이 있는지 물어볼 수 있을 것(What about the local leather supplier ~ We could ask them whether they have enough for ten sofas)이라고 했으므로 정답은 (A)이다."}, {"n": 46, "q": "Why is the woman opposed to making a change?", "opts": ["She has contracts with clients.", "She is concerned about quality.", "Overhead expenses will increase.", "A license will expire soon."], "ans": 1, "ko": "여자가 마지막 대사에서 남자가 언급한 공급업체의 가죽 품질이 그렇게 인상적이지 않았다며, 차라리 기다리는 게 좋겠다(I wasn't very impressed with the quality of their leather. I'd rather wait)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "W", "en": "I spoke to the Mancini brothers. They just shipped our leather order—the hazelnut color. But it'll take a while to arrive. We don't have enough in stock to complete the ten sofa orders that we've received the past few days.", "ko": "맨시니 브러더스와 이야기했습니다. 헤이즐넛 색상 가죽 주문을 막 발송했대요. 그런데 도착하려면 시간이 좀 걸릴 거예요. 지난 며칠 동안 받은 10개의 소파 주문을 완료할 수 있을 만큼 재고가 충분하지 않아요."}, {"sp": "M", "en": "What about the local leather supplier that brought us some samples last week? We could ask them whether they have enough for ten sofas.", "ko": "지난주에 샘플을 가져온 지역 가죽 공급업체는 어떤가요? 소파 10개를 만들 만큼 충분한 양이 있는지 물어볼 수 있을 거예요."}, {"sp": "W", "en": "To be honest, I wasn't very impressed with the quality of their leather. I'd rather wait. I'll reach out to the customers about the delay.", "ko": "솔직히, 그곳 가죽의 품질이 그렇게 인상적이지 않았어요. 차라리 기다리는 게 좋겠어요. 지연에 대해 고객들께 연락을 드릴게요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test_05-47-49.mp3", "qs": [{"n": 47, "q": "What are the speakers meeting to discuss?", "opts": ["Safety regulations", "Equipment upgrades", "Budget cuts", "Consultant recommendations"], "ans": 3, "ko": "여자가 첫 대사에서 컨설팅 업체로부터 결과를 받았다며, 데님 청바지의 판매를 늘릴 수 있는 방법에 대한 몇 가지 아이디어가 있다(I just got the results from the consulting firm we hired. They have some ideas ~)고 했고, 관련된 이야기를 이어 가고 있으므로 정답은 (D)이다."}, {"n": 48, "q": "What does the man mean when he says, \"it takes a lot of effort to develop and launch new styles\"?", "opts": ["He is excited about a challenge.", "He is surprised at a competitor's choices.", "He is doubtful about a suggestion.", "He thinks more employees should be hired."], "ans": 2, "ko": "여자가 브랜드를 새로운 스타일이나 색상으로 업데이트할 시기라고 목표 고객들이 생각한다고 하자, 남자가 새로운 스타일을 개발하고 출시하려면 많은 노력이 필요하다고 말하며 그 제안에 대해 회의적인 태도를 보이고 있으므로 정답은 (C)이다."}, {"n": 49, "q": "", "opts": [], "ans": 1, "ko": ""}], "script": [{"sp": "W", "en": "Thanks for coming in, Marcos. I just got the results from the consulting firm we hired. They have some ideas about how we can increase sales of our denim blue jeans.", "ko": "와 주셔서 감사합니다, 마르코스. 우리가 고용한 컨설팅 업체로부터 막 결과를 받았어요. 데님 청바지의 판매를 늘릴 수 있는 방법에 대한 몇 가지 아이디어가 있더군요."}, {"sp": "M", "en": "I hope so. What does our target audience want?", "ko": "그렇기를 바랍니다. 우리 목표 고객들은 무엇을 원하나요?"}, {"sp": "W", "en": "Well, they think it's time we updated our brand with new styles or colors.", "ko": "음, 그들은 우리가 새로운 스타일이나 색상으로 브랜드를 업데이트할 시기라고 생각해요."}, {"sp": "M", "en": "You know, it takes a lot of effort to develop and launch new styles.", "ko": "알잖아요. 새로운 스타일을 개발하고 출시하려면 많은 노력이 필요해요."}, {"sp": "W", "en": "Yes. But, if we don't do it, another company will.", "ko": "네. 하지만 우리가 그렇게 하지 않으면, 다른 회사가 할 겁니다."}, {"sp": "M", "en": "You're right. I'll ask Junko to come up with some new designs for us to consider.", "ko": "맞는 말씀입니다. 준코에게 우리가 고려할 수 있게 새로운 디자인 몇 개를 제안해 달라고 요청할게요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Am", "audio": "Test_05-50-52.mp3", "qs": [{"n": 50, "q": "Why did the man miss a meeting?", "opts": ["He was stuck in traffic.", "He had a medical appointment.", "He was speaking with a client.", "He was away on vacation."], "ans": 3, "ko": "세부 사항 관련 – 남자가 회의에 놓친 이유. 남자가 첫 대사에서 월간 회의와 관련해 이야기하면서 휴가에서 복귀해서 아직 업무를 따라잡고 있다(I'm back from vacation and still catching up)고 했으므로 정답은 (D)이다."}, {"n": 51, "q": "Which sport does the speakers' organization promote?", "opts": ["Tennis", "Volleyball", "Swimming", "Gymnastics"], "ans": 0, "ko": "세부 사항 관련 – 화자들의 단체가 장려하는 스포츠. 여자가 첫 대사에서 젊은 선수들을 위한 테니스 캠프(the tennis camp for young players)와 관련해 이야기하고 있으므로 정답은 (A)이다."}, {"n": 52, "q": "Why were T-shirts ordered early?", "opts": ["To avoid potential delays", "To get free delivery", "To receive a discount", "To meet heavy demand"], "ans": 2, "ko": "세부 사항 관련 – 티셔츠를 일찍 주문한 이유. 여자가 마지막 대사에서 티셔츠를 아주 일찍 주문했다며, 그렇게 해서 가격의 절반을 할인받았다(~ the T-shirts were ordered very early. That way we received half off the price ~)고 했으므로 정답은 (C)이다. Paraphrasing: 대화의 half off the price → 정답의 a discount"}], "script": [{"sp": "M", "en": "Hi, Gabriela. Thanks for agreeing to give me the highlights of the budget discussion from the monthly meeting. I'm back from vacation and still catching up.", "ko": "안녕하세요, 가브리엘라. 월간 회의의 예산 논의 관련 중점 사항들을 알려 주시는 데 동의해 주셔서 감사합니다. 휴가에서 복귀해서 아직 업무를 따라잡고 있어요."}, {"sp": "W", "en": "Sure. Here's a copy of the report. Everyone on our organization's board at Tennis United agreed to the fee increase for the tennis camp for young players.", "ko": "별말씀을요. 여기 보고서 사본입니다. 테니스 유나이티드의 이사회 구성원 모두가 젊은 선수들을 위한 테니스 캠프의 요금 인상에 동의했습니다."}, {"sp": "M", "en": "Good. And why do we have T-shirts listed as an expense item?", "ko": "좋습니다. 그리고 왜 지출 항목에 티셔츠가 있나요?"}, {"sp": "W", "en": "Although the next tournament's in the fall, the T-shirts were ordered very early. That way we received half off the price, since the supplier wanted to get rid of his summer inventory.", "ko": "다음 토너먼트가 가을에 있긴 하지만, 티셔츠를 아주 일찍 주문했습니다. 그렇게 해서 가격의 절반을 할인받았어요. 공급업자가 여름 재고를 소진하고 싶어 했거든요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "3인 대화 W-Am / M-Au / M-Cn", "audio": "Test_05-53-55.mp3", "qs": [{"n": 53, "q": "What industry do the speakers most likely work in?", "opts": ["Energy", "Finance", "Construction", "Manufacturing"], "ans": 2, "ko": "전체 내용 관련 – 화자들의 근무 업계. 여자가 첫 대사에서 모리스빌 다리의 보수를 위한 회사의 입찰(our bid to renovate the Morrisville Bridge)을 언급했으므로 정답은 (C)이다."}, {"n": 54, "q": "What is the reason a company did not get a contract?", "opts": ["Some costs were too high.", "A facility failed an inspection.", "Some paperwork was submitted late.", "A competitor can complete a project faster."], "ans": 3, "ko": "세부 사항 관련 – 계약을 따내지 못한 이유. 두 번째 남자가 첫 대사에서 계약을 따내지 못한 이유에 대해 다른 건설 회사가 더 짧은 일정으로 제안서를 제출했다(~ another construction company submitted a proposal with a shorter timeline)고 했으므로 정답은 (D)이다. Paraphrasing: 대화의 another construction company submitted a proposal with a shorter timeline → 정답의 A competitor can complete a project faster."}, {"n": 55, "q": "What does the woman ask the men to do?", "opts": ["Visit a facility", "Conduct some research", "Rewrite a proposal", "Contact some vendors"], "ans": 1, "ko": "세부 사항 관련 – 여자의 요청 사항. 여자가 마지막 대사에서 남자들에게 다음 회의 전까지 조사를 해 줄 것(Can you two do some research before our next meeting?)을 요청했으므로 정답은 (B)이다. Paraphrasing: 대화의 do → 정답의 Conduct"}], "script": [{"sp": "W", "en": "The first item on today's meeting agenda is our bid to renovate the Morrisville Bridge. Do we have an update on that yet?", "ko": "오늘 회의의 첫 번째 안건은 모리스빌 다리의 보수를 위한 우리의 입찰 건입니다. 혹시 이에 관한 새로운 소식이 있나요?"}, {"sp": "M", "en": "Yes—unfortunately we didn't get the contract.", "ko": "네, 유감스럽게도 계약을 따내지 못했습니다."}, {"sp": "M", "en": "Yes, the only explanation given was that another construction company submitted a proposal with a shorter timeline.", "ko": "네, 전달받은 유일한 설명은 다른 건설 회사가 더 짧은 일정으로 제안서를 제출했다는 것이었습니다."}, {"sp": "W", "en": "So, what do we know about this competitor? Have they worked on other local projects?", "ko": "그럼, 그 경쟁사에 대해 우리가 알고 있는 건 무엇인가요? 지역 내 다른 프로젝트들도 작업했나요?"}, {"sp": "M", "en": "The only thing I heard was their name—CDQ Construction Company.", "ko": "유일하게 들은 것은 그곳 이름인데, CDQ 건설 회사입니다."}, {"sp": "W", "en": "Well, I'd like to know more about them. Can you two do some research before our next meeting?", "ko": "음, 그 회사에 대해 더 많이 알았으면 합니다. 두 분이 다음 회의 전까지 조사를 해 주시겠어요?"}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test_05-56-58.mp3", "qs": [{"n": 56, "q": "What did the company do last month?", "opts": ["It opened a second location.", "It merged with another business.", "It launched a new product.", "It conducted an employee survey."], "ans": 3, "ko": "세부 사항 관련 – 회사가 지난달에 한 일. 여자가 첫 대사에서 지난달 직원 설문 조사 결과가 정리된 걸 봤는지(Did you see that the results of last month's employee survey have been compiled?) 물었으므로 정답은 (D)이다."}, {"n": 57, "q": "Why does the man say, \"we do have money available in the budget\"?", "opts": ["To request another budget analysis", "To suggest hiring additional employees", "To agree with a proposed renovation", "To recommend an increase in advertising"], "ans": 2, "ko": "화자의 의도 파악 – 예산에 쓸 수 있는 돈이 있다는 말의 의도. 여자가 두 번째 대사에서 벽을 철거해서 휴게실을 확장할 수 있을 것(~ we could enlarge the break room by having the wall taken down ~)이라고 제안하는 것에 대해 남자가 인용문을 언급하고 있다. 이는 예산에 남은 돈이 있기 때문에 여자가 제안하는 확장 공사를 할 수 있다는 뜻이므로 정답은 (C)이다."}, {"n": 58, "q": "What does the man say he has to do this afternoon?", "opts": ["Have his car repaired", "Give a presentation", "Go to a dentist appointment", "Attend a reception"], "ans": 2, "ko": "세부 사항 관련 – 남자가 오늘 오후에 할 일. 남자가 마지막 대사에서 치과 진료를 받아야 해서 오늘 오후에는 할 수 없다(I can't do it this afternoon, since I need to see a dentist ~)고 했으므로 정답은 (C)이다. Paraphrasing: 대화의 see a dentist → 정답의 Go to a dentist appointment"}], "script": [{"sp": "W", "en": "Did you see that the results of last month's employee survey have been compiled? All the staff feedback is available.", "ko": "지난달 직원 설문 조사 결과가 정리된 걸 보셨나요? 모든 직원 의견을 확인할 수 있어요."}, {"sp": "M", "en": "Yes, and I just finished reviewing the comments.", "ko": "네, 방금 의견 검토를 마쳤습니다."}, {"sp": "W", "en": "You know, I noticed one recurring complaint. The size of the break room is too small. Perhaps we could enlarge the break room by having the wall taken down between it and the meeting room next door.", "ko": "있잖아요, 한 가지 반복되는 불만을 알게 되었어요. 휴게실의 크기가 너무 작아요. 아마 휴게실과 옆에 있는 회의실 사이의 벽을 철거해서 확장할 수 있을 거예요."}, {"sp": "M", "en": "Well, we do have money available in the budget.", "ko": "음, 예산에 쓸 수 있는 돈이 있어요."}, {"sp": "W", "en": "Then could you reach out to your contact at the construction company?", "ko": "그렇다면 건설 회사의 담당자에게 연락해 주시겠어요?"}, {"sp": "M", "en": "I can't do it this afternoon, since I need to see a dentist, but I will definitely make the call.", "ko": "치과 진료를 받아야 해서 오늘 오후에는 할 수 없지만 꼭 전화할게요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test_05-59-61.mp3", "qs": [{"n": 59, "q": "Where does the woman work?", "opts": ["At a recycling company", "At an appliance store", "At a manufacturing company", "At an architectural firm"], "ans": 0, "ko": "전체 내용 관련 – 여자의 근무 장소. 여자가 첫 대사에서 항스 금속 재활용 회사에 전화해 줘서 감사하다(Thanks for calling Hang's Metal Recycling Company)고 했으므로 정답은 (A)이다."}, {"n": 60, "q": "What does the man ask the woman to do?", "opts": ["Revise a contract", "Match a competitor's offer", "Refund a delivery fee", "Sign in at a security desk"], "ans": 1, "ko": "세부 사항 관련 – 남자의 요청 사항. 남자가 두 번째 대사에서 다른 재활용 센터를 언급하면서 그곳 가격에 맞춰 줄 의향이 있는지(there's another recycling center ~ Would you be willing to match their price?) 묻고 있으므로 정답은 (B)이다. Paraphrasing: 대화의 match their price → 정답의 Match a competitor's offer"}, {"n": 61, "q": "What does the man say he will do this afternoon?", "opts": ["Conduct an inspection", "Sign a document", "Deliver some materials", "Update a Web site"], "ans": 2, "ko": "세부 사항 관련 – 남자가 오늘 오후에 할 일. 남자가 마지막 대사에서 오늘 오후에 고철을 가져가겠다(I'll bring the metal to you this afternoon, then)고 했으므로 정답은 (C)이다. Paraphrasing: 대화의 bring the metal → 정답의 Deliver some materials"}], "script": [{"sp": "W", "en": "Thanks for calling Hang's Metal Recycling Company. How can I help you?", "ko": "항스 금속 재활용 회사에 전화해 주셔서 감사합니다. 무엇을 도와드릴까요?"}, {"sp": "M", "en": "Hi. I'm with Shannak Construction Company. We've got a lot of brass metal scrap from a recent remodeling job. Are you currently buying metal scrap?", "ko": "안녕하세요. 저는 샤낵 건설 회사에 근무하는 사람입니다. 최근 리모델링 공사에서 황동 고철이 많이 생겼어요. 현재 고철을 매입하고 계신가요?"}, {"sp": "W", "en": "Yes, we are. We currently pay two dollars a pound.", "ko": "네, 그렇습니다. 현재 1파운드당 2달러를 지급하고 있습니다."}, {"sp": "M", "en": "Oh, there's another recycling center that pays two dollars and twenty-five cents a pound. Would you be willing to match their price?", "ko": "아, 1파운드당 2달러 25센트를 지급하는 다른 재활용 센터가 있어요. 그곳 가격에 맞춰 주실 의향이 있으신가요?"}, {"sp": "W", "en": "Yes, we have a price-match guarantee.", "ko": "네, 저희는 가격 일치 보장제를 시행합니다."}, {"sp": "M", "en": "Great. I'll bring the metal to you this afternoon, then.", "ko": "잘됐네요. 그럼 오늘 오후에 고철을 가져갈게요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "W-Br / M-Cn", "audio": "Test_05-62-64.mp3", "qs": [{"n": 62, "q": "Look at the graphic. Which project phase was just completed?", "opts": ["Phase 1", "Phase 2", "Phase 3", "Phase 4"], "ans": 1, "ko": "시각 정보 연계 – 막 완료된 단계. 남자가 첫 대사에서 이제 굴착 작업이 끝났다(The drilling is done now)고 했는데, 프로젝트 계획표에서 굴착 작업(Drill through rock)은 2단계(Phase 2)에 해당하므로 정답은 (B)이다."}, {"n": 63, "q": "What does the woman ask the man to do?", "opts": ["Request an earlier delivery date", "Consult with a safety inspector", "Post some construction plans", "Forward an invoice"], "ans": 0, "ko": "세부 사항 관련 – 여자의 요청 사항. 여자가 세 번째 대사에서 배송이 더 신속히 될 수 있는지 확인해 보자며, 그렇게 해 줄 수 있는지(Let's see if the shipment can be expedited. Can you do that?) 묻고 있으므로 정답은 (A)이다. Paraphrasing: 대화의 the shipment can be expedited → 정답의 an earlier delivery date"}, {"n": 64, "q": "What does the woman intend to do next?", "opts": ["Review some data", "Move a vehicle", "Increase the size of a crew", "Contact the management team"], "ans": 3, "ko": "세부 사항 관련 – 여자가 다음에 할 일. 여자가 마지막 대사에서 경영진에 이메일을 쓰겠다(I'm going to write an e-mail to management ~)고 했으므로 정답은 (D)이다. Paraphrasing: 대화의 write an e-mail → 정답의 Contact"}], "script": [{"sp": "W", "en": "Hi. I just got off the phone with management. They're not happy. The construction of the train tunnel isn't progressing fast enough.", "ko": "안녕하세요. 방금 경영진과 통화를 마쳤어요. 기분이 좋지 않으시네요. 기차 터널 공사가 충분히 빠르게 진행되고 있지 않아요."}, {"sp": "M", "en": "Yeah, I'm not surprised. The drilling is done now. The thing is, we can't start installing the support columns until we have all the materials for the concrete.", "ko": "네, 놀랍지 않아요. 이제 굴착 작업이 끝났어요. 문제는 콘크리트를 위한 재료가 모두 준비되기 전에는 지지 기둥 설치를 시작할 수 없다는 것입니다."}, {"sp": "W", "en": "When are the materials going to get here?", "ko": "재료는 언제 오나요?"}, {"sp": "M", "en": "A week, maybe two.", "ko": "일주일, 어쩌면 2주요."}, {"sp": "W", "en": "Let's see if the shipment can be expedited. Can you do that?", "ko": "배송이 더 신속히 될 수 있는지 확인해 봅시다. 그렇게 해 주실 수 있으세요?"}, {"sp": "M", "en": "Sure. I'll call the supplier to ask about getting it here sooner.", "ko": "물론이죠. 공급 업체에 전화해서 더 빨리 도착할 수 있는지 물어볼게요."}, {"sp": "W", "en": "In the meantime, I'm going to write an e-mail to management to explain how we're attempting to resolve the situation.", "ko": "그동안, 저는 경영진에 이메일을 써서 상황을 어떻게 해결하려고 하는지 설명하겠습니다."}], "gimg": "ets_t5_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "M-Au / W-Am", "audio": "Test_05-65-67.mp3", "qs": [{"n": 65, "q": "What type of business do the speakers work for?", "opts": ["A restaurant", "A law firm", "An office-supply store", "A flower shop"], "ans": 0, "ko": "전체 내용 관련 – 화자들의 근무 업체. 남자가 첫 대사에서 우리 레스토랑(our restaurant)이라고 했으므로 정답은 (A)이다."}, {"n": 66, "q": "Look at the graphic. In which area of the city does the business make most of its deliveries?", "opts": ["The waterfront district", "The historic district", "The residential district", "The downtown district"], "ans": 3, "ko": "시각 정보 연계 – 배달을 가장 많이 하는 구역. 여자가 두 번째 대사에서 주요 배달 구역에 주차하는 데 1시간에 최대 15달러(Parking in our main delivery area is up to fifteen dollars an hour)라고 했는데, 안내도에서 15달러는 Downtown District에 해당하므로 정답은 (D)이다."}, {"n": 67, "q": "(질문 미표시 - 다음 페이지 이어짐)", "opts": [], "ans": 1, "ko": ""}], "script": [{"sp": "M", "en": "The city just posted its new parking rates, and we need to talk about how they'll affect our restaurant's food delivery service. I'm worried we'll lose money because we'll need to pay more for parking while the delivery driver takes the food to customers.", "ko": "시에서 방금 새 주차 요금을 공시했는데, 그게 우리 레스토랑의 음식 배달 서비스에 어떤 영향을 미칠지 이야기해 봐야 합니다. 배달 기사가 고객에게 음식을 가져다주는 동안 주차비를 더 내야 해서 손해를 볼까 봐 걱정입니다."}, {"sp": "W", "en": "Wow. Parking in our main delivery area is up to fifteen dollars an hour? That is a problem. But offering free delivery attracts a lot of business. What else can we do to lower expenses?", "ko": "와우. 우리 주요 배달 구역에 주차하는 데 1시간에 최대 15달러인 건가요? 이건 문제네요. 하지만 무료 배달 서비스를 제공하는 게 많은 거래를 유치해요. 비용을 낮추기 위해 또 무엇을 할 수 있죠?"}, {"sp": "M", "en": "We could start using bicycle delivery whenever possible. That should help.", "ko": "가능할 때는 자전거 배달 서비스를 이용할 수 있을 겁니다. 도움이 될 거예요."}, {"sp": "W", "en": "Good idea. I'll talk to our drivers to see who's willing to switch to bicycle deliveries for customers nearby. Some people really like the exercise.", "ko": "좋은 생각입니다. 제가 기사들과 이야기해서 누가 근처에 있는 고객들을 대상으로 자전거 배달 서비스로 바꿀 의향이 있는지 알아볼게요. 어떤 사람들은 운동을 정말 좋아하거든요."}], "gimg": "ets_t5_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "M-Au / W-Br", "audio": "Test_05-68-70.mp3", "qs": [{"n": 68, "q": "Who most likely is the woman?", "opts": ["A hotel manager", "An interior designer", "A construction worker", "A real estate agent"], "ans": 1, "ko": "남자가 첫 대사에서 여자의 소속 업체를 인테리어 디자인 회사(your interior design firm)라고 했으므로 정답은 (B)이다."}, {"n": 69, "q": "Look at the graphic. Which step does the man ask about?", "opts": ["Step 1", "Step 2", "Step 3", "Step 4"], "ans": 0, "ko": "남자가 두 번째 대사에서 정말 천장 채광창이 필요하다고 생각하는지(Do you really think we need skylights?) 물었는데, 제안서에서 천장 채광창 설치(Install skylights)는 1단계(Step 1)이므로 정답은 (A)이다."}, {"n": 70, "q": "What will the man most likely do next?", "opts": ["Send a contract", "Go to the lobby", "Look at some photographs", "Review a cost estimate"], "ans": 3, "ko": "여자가 마지막 대사에서 4페이지로 넘기면 세부 비용 내역이 보일 것(If you turn to page four, you'll see the cost breakdown)이라고 했으므로 정답은 (D)이다."}], "script": [{"sp": "M", "en": "When customers walk into Southern Regional Bank, I want them to feel confident about entrusting their money to us. As I mentioned the last time we met, I'm hoping your interior design firm can give our lobby a more polished, professional look.", "ko": "고객들이 서던 리저널 은행으로 들어올 때, 우리에게 돈을 맡기는 것에 확신이 들게 하고 싶습니다. 지난번에 만났을 때 언급했던 것처럼, 귀하의 인테리어 디자인 회사에서 로비를 더 세련되고 전문적인 모습으로 만들어 주셨으면 해요."}, {"sp": "W", "en": "Our proposal does just that. Here—take a look. The cover page includes a summary of the renovations.", "ko": "저희 제안서가 바로 그렇습니다. 여기, 보시죠. 표지에 개조 공사 요약이 있습니다."}, {"sp": "M", "en": "Hmm. Do you really think we need skylights? That would be a big expense.", "ko": "흠. 정말 천장 채광창이 필요하다고 생각하시나요? 이건 많은 비용이 들 텐데요."}, {"sp": "W", "en": "There aren't many windows in your lobby, so it's the best way to bring more natural light into the room. Besides, our proposed renovations would actually come in under budget. If you turn to page four, you'll see the cost breakdown.", "ko": "로비에 창문이 많지 않아서, 자연광을 로비로 들어오게 하기 위한 최선의 방법입니다. 게다가, 저희가 제안한 개조 공사는 실제로 예산 범위 안에 있습니다. 4페이지로 넘기면, 세부 비용 내역이 보일 겁니다."}], "gimg": "ets_t5_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test_05-71-73.mp3", "qs": [{"n": 71, "q": "Who most likely is the speaker?", "opts": ["A department manager", "A news reporter", "A marketing consultant", "A computer programmer"], "ans": 0, "ko": "화자가 초반부에 회사 월간 회의에 온 것을 환영한다고 했고, 매출 수치에 관한 보고를 언급하고, IT팀에 축하를 전하는(Welcome to the monthly company staff meeting. Before I begin my report ~ I want to congratulate our fantastic IT team!) 등 회의를 진행하고 있다. 이는 부서의 책임자가 할 수 있는 일에 해당하므로 정답은 (A)이다."}, {"n": 72, "q": "Why does the speaker congratulate a team?", "opts": ["For keeping expenses low", "For creating a useful tool", "For meeting a tight deadline", "For achieving the most sales"], "ans": 1, "ko": "화자가 중반부에 IT팀을 축하하면서 그들이 만든 판매 추적 시스템은 다른 지점의 동료들과 결과를 쉽게 공유할 수 있게 해 준다(~ I want to congratulate our fantastic IT team! The sales tracking system they built allows us to easily share results ~)고 했으므로 정답은 (B)이다."}, {"n": 73, "q": "What are the listeners required to do?", "opts": ["Register for some training", "Review a floor plan", "Participate in a mentoring program", "Provide copies of certifications"], "ans": 0, "ko": "화자가 중반부에 모든 직원이 참석해야 하는 교육을 언급하며, 등록용 링크가 오후에 발송될 것(All employees are required to attend a training session ~ A registration link will be sent out this afternoon)이라고 했으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "Welcome to the monthly company staff meeting. Before I begin my report on last month's sales figures, I want to congratulate our fantastic IT team! The sales tracking system they built allows us to easily share results with colleagues from other branches. All employees are required to attend a training session on how to use it. A registration link will be sent out this afternoon. Now, let's look at last month's figures. We need to decide if we're ready to expand into more markets.", "ko": "월간 회사 직원회의에 오신 것을 환영합니다. 지난달 매출 수치에 관한 보고를 시작하기에 앞서, 환상적인 IT팀에 축하를 전하고 싶습니다! 그들이 만든 판매 추적 시스템은 다른 지점의 동료들과 결과를 쉽게 공유할 수 있게 해 줍니다. 모든 직원은 이용 방법에 관한 교육에 참석해야 합니다. 등록용 링크가 오늘 오후에 발송될 겁니다. 이제, 지난달 수치를 보시겠습니다. 우리는 더 많은 시장으로 사업을 확대할 준비가 되어 있는지 결정해야 합니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test_05-74-76.mp3", "qs": [{"n": 74, "q": "What are the listeners invited to do?", "opts": ["Download a calendar", "Reserve tickets", "Submit a picture", "Share a story"], "ans": 3, "ko": "화자가 초반부에 출연을 원해서 전화했다면 이야기를 들어 보고 싶다며, 이야기 녹음을 위해 1번을 눌러 달라(If you are calling because you'd like to appear on our show, we'd love to hear your story! To record your story idea, please press one)고 했으므로 정답은 (D)이다."}, {"n": 75, "q": "What guideline does the speaker emphasize?", "opts": ["Recordings must be kept short.", "Electronic devices must be turned off.", "Professional references must be provided.", "Vehicles must be parked in a designated area."], "ans": 0, "ko": "화자가 중반부에 유의해 달라며, 메시지는 60초 이내로 남겨야 한다(Please note: it is necessary to keep your message under 60 seconds)고 했으므로 정답은 (A)이다."}, {"n": 76, "q": "According to the speaker, what may cause a delay?", "opts": ["Bad weather", "Holidays", "A construction project", "Staff changes"], "ans": 1, "ko": "화자가 후반부에 휴일 전후로는 대기 시간이 더 길어질 것으로 예상된다(~ with longer wait times expected around holidays)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "M", "en": "Hello. You've reached the communications team of Business As Usual, the talk show about starting a new business. If you are calling because you'd like to appear on our show, we'd love to hear your story! To record your story idea, please press one. Please note: it is necessary to keep your message under 60 seconds. Submissions that are more than a minute long will not be reviewed. The typical timeline for the review process is two weeks, with longer wait times expected around holidays.", "ko": "안녕하세요. 새로운 사업을 시작하는 것에 관한 토크쇼, 〈비즈니스 애즈 유주얼〉의 커뮤니케이션 팀입니다. 쇼에 출연하고 싶어서 전화하셨다면, 귀하의 이야기를 듣고 싶습니다! 귀하의 이야기를 녹음하시려면, 1번을 눌러 주세요. 유의해 주시기 바랍니다. 메시지는 60초 이내로 남겨 주셔야 합니다. 1분이 넘는 제출물은 검토되지 않을 것입니다. 검토 과정의 일반적인 일정은 2주이며, 휴일 전후로는 대기 시간이 더 길어질 것으로 예상됩니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test_05-77-79.mp3", "qs": [{"n": 77, "q": "What is the focus of a tour?", "opts": ["Food", "Architecture", "Nature", "Art"], "ans": 0, "ko": "화자가 초반부에 스프링필드 시내 요리 투어에 온 것을 환영한다(Welcome to the culinary tour of downtown Springfield)고 했으므로 정답은 (A)이다."}, {"n": 78, "q": "What does the speaker imply when she says, \"we have such a large group today\"?", "opts": ["She is happy about the popularity of a tour.", "She will need to use a microphone.", "An additional tour guide is needed.", "A shop is not big enough for everyone."], "ans": 3, "ko": "화자가 중반부에 평소라면 젤다스 베이커리 내부로 데리고 가서 유명한 옥수수 머핀을 시식하는 것으로 시작한다(Normally I'd start by taking you inside Zelda's Bakery ~)고 말한 뒤로 인용문을 언급하면서 대신 노천 시장으로 곧장 향하겠다(Instead, we're going to head directly to the open-air market)고 했다. 이는 단체 규모가 너무 커서 평소대로 베이커리에 갈 수 없다는 뜻이므로 정답은 (D)이다."}, {"n": 79, "q": "What will a ticket allow the listeners to do?", "opts": ["Attend a performance", "Visit a museum", "Participate in a class", "Enter a contest"], "ans": 1, "ko": "화자가 후반부에 투어 티켓을 보관하라며, 지역 박물관에 1회 무료로 입장할 수 있다(~ remember to keep your tour ticket. It's good for one free entry at the local museum)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "W", "en": "Welcome to the culinary tour of downtown Springfield. Today, you'll taste a variety of local foods. Normally I'd start by taking you inside Zelda's Bakery to try one of their famous corn muffins, but we have such a large group today. Instead, we're going to head directly to the open-air market. There you'll find a wide selection of the homemade breads, jams, and pastries that we're noted for. After that, we'll head to the original Springfield cornmill, which is still in use today. And remember to keep your tour ticket. It's good for one free entry at the local museum.", "ko": "스프링필드 시내 요리 투어에 오신 것을 환영합니다. 오늘, 여러분께서는 다양한 지역 음식을 맛보실 것입니다. 평소라면 제가 젤다스 베이커리 내부로 모시고 가서 유명한 옥수수 머핀을 시식하는 것으로 시작하겠지만, 오늘은 단체 규모가 아주 큽니다. 대신, 노천 시장으로 곧장 향하겠습니다. 그곳에서 유명한 집에서 만든 빵과 잼, 그리고 패스트리 등 다양한 종류의 제품을 만날 수 있습니다. 그 후에는, 최초의 스프링필드 옥수수 제분소로 향할 텐데요. 이곳은 지금도 여전히 이용되고 있습니다. 그리고 투어 티켓을 보관하는 것을 기억하세요. 지역 박물관에 1회 무료로 입장할 수 있습니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test_05-80-82.mp3", "qs": [{"n": 80, "q": "What industry was the Novikov Award created for?", "opts": ["Aviation", "Chemical engineering", "Medical research", "Television production"], "ans": 0, "ko": "화자가 초반부에 노비코브 상을 소개하면서 매년 항공 산업에 뛰어난 공헌을 한 회사에 주어진다(It is given each year to a company that has made outstanding contributions to the aviation industry)고 했으므로 정답은 (A)이다."}, {"n": 81, "q": "Why was this year's award recipient selected?", "opts": ["For launching a unique advertising campaign", "For developing a successful training program", "For maintaining a perfect safety record", "For making a scientific discovery"], "ans": 1, "ko": "화자가 중반부에 제니스 항공의 수습 프로그램은 항공기 정비 및 수리 분야에서 일할 수백 명의 근로자를 교육해 왔다(Zenith Aviation's apprenticeship program has trained hundreds of workers ~)며, 많은 업체들이 이 프로그램을 모방했다고 했으므로 정답은 (B)이다."}, {"n": 82, "q": "What does the speaker ask the listeners to do?", "opts": ["Get ready to watch a video", "Applaud the winner", "Share copies of a handout", "Read a set of directions"], "ans": 0, "ko": "화자가 후반부에 프로그램의 효과를 집중 조명하는 영상을 볼 수 있도록 스크린을 주목하라(~ please direct your attention to the screen for a video highlighting the program's effectiveness)고 했으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "The Novikov Award is named after Maksim Novikov, the founder of Novikov Aviation. It is given each year to a company that has made outstanding contributions to the aviation industry. The company chosen for the award this year was frustrated by the lack of qualified job applicants and decided to do something about it. Zenith Aviation's apprenticeship program has trained hundreds of workers for careers in aircraft maintenance and repair. Dozens of firms nationwide have copied the program. Before I present the award, please direct your attention to the screen for a video highlighting the program's effectiveness.", "ko": "노비코브 상은 노비코브 항공의 설립자, 막심 노비코브의 이름을 따왔습니다. 이 상은 매년 항공 산업에 뛰어난 공헌을 한 회사에 주어집니다. 올해 수상 업체로 선정된 회사는 자격을 갖춘 구직자들의 부족에 좌절감을 겪었고, 뭔가 해 보기로 결정했습니다. 제니스 항공의 수습 프로그램은 항공기 정비 및 수리 분야에서 일할 수백 명의 근로자를 교육해 왔습니다. 전국적으로 수십 곳의 업체들이 이 프로그램을 모방했습니다. 시상하기에 앞서, 이 프로그램의 효과를 집중 조명하는 영상을 보실 수 있도록 스크린을 주목해 주시기 바랍니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test_05-83-85.mp3", "qs": [{"n": 83, "q": "Who is the speaker presenting to?", "opts": ["Loan officers", "Construction workers", "City council members", "Bus drivers"], "ans": 2, "ko": "화자가 초반부에 이번 시 의회 회의에서 발언할 수 있는 기회를 줘서 감사하다(Thank you for allowing me the opportunity to speak at this city council meeting)고 했으므로 정답은 (C)이다."}, {"n": 84, "q": "What does the speaker say about some existing structures?", "opts": ["They are in disrepair.", "They are very small.", "They were not assembled correctly.", "They were installed last year."], "ans": 0, "ko": "화자가 중반부에 현재 쉼터들은 상태가 좋지 않다며, 유리에 금이 가거나 벤치가 부서진 곳이 많다(~ the current shelters aren't in good shape. Many of them have cracked glass and broken benches)고 했으므로 정답은 (A)이다."}, {"n": 85, "q": "Why does the speaker say, \"its models include a display for advertisements\"?", "opts": ["To respond to a request for information", "To justify a cost", "To express surprise", "To suggest adding to a product line"], "ans": 1, "ko": "화자가 왜 \"이곳의 모델에는 광고 디스플레이가 포함되어 있습니다\"라고 말하는지를 묻는 문제로, 비용이 덜 드는 옵션도 있지만(While less expensive options are available) 이곳의 모델에는 광고 디스플레이가 포함되어 있고, 이 쉼터들은 새로운 수입원을 제공해 줄 수 있다는 흐름으로 볼 때, 더 비싼 선택을 하는 이유(비용)를 정당화하려는 의도이므로 정답은 (B)이다."}], "script": [{"sp": "M", "en": "Thank you for allowing me the opportunity to speak at this city council meeting. On behalf of the transportation department, I'd like to present a proposal to fund the replacement of all 350 bus-stop shelters in our city. We feel this is a worthwhile investment because the current shelters aren't in good shape. Many of them have cracked glass and broken benches. We want to go with Urban Retreat because its shelters are made of durable materials. While less expensive options are available, its models include a display for advertisements. These shelters could provide the city with a new source of income.", "ko": "이번 시 의회 회의에서 발언할 수 있는 기회를 주셔서 감사합니다. 교통국을 대표해, 저는 우리 시에 있는 버스 정류장 쉼터 350곳 모두를 교체하기 위한 자금을 제공하자는 제안을 발표하고자 합니다. 이것이 가치 있는 투자라고 생각하는데, 현재 쉼터들은 상태가 좋지 않기 때문입니다. 유리에 금이 가거나 벤치가 부서진 곳이 많습니다. 저희는 어번 리트리트를 이용하고자 하는데, 이곳의 쉼터는 내구성이 좋은 자재로 만들어지기 때문입니다. 비용이 덜 드는 옵션도 있지만, 이곳의 모델에는 광고 디스플레이가 포함되어 있습니다. 이 쉼터들은 우리 시에 새로운 수입원을 제공해 줄 수 있을 것입니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test_05-86-88.mp3", "qs": [{"n": 86, "q": "What does the speaker's company sell?", "opts": ["Clothing", "Flowers", "Toys", "Wallpaper"], "ans": 3, "ko": "화자가 초반부에 새 벽지 패턴과 관련해 전화했다(I'm calling about the new wallpaper patterns ~)고 했고, 벽지들이 모두 제작 승인이 될 거라고 거의 확신한다(I'm almost certain that all of those will be approved for production ~)고 했으므로 정답은 (D)이다."}, {"n": 87, "q": "Why does the speaker praise the listener's team?", "opts": ["They stayed under budget.", "They won an award.", "They showed creativity.", "They completed some work on schedule."], "ans": 2, "ko": "화자가 중반부에 청자의 디자인 팀에 정말 창의적인 사람들이 있다(You have some truly creative people on your design team)고 했으므로 정답은 (C)이다."}, {"n": 88, "q": "Why does the speaker say, \"we have a full supply of those in stock\"?", "opts": ["To report that inventory has been completed", "To offer to share some supplies with another store", "To explain that some designs are not needed", "To confirm that a customer's order can be filled"], "ans": 2, "ko": "화자가 후반부에 청자가 보낸 동물 주제의 프린트(the animal-themed prints you sent)를 언급하면서 인용문을 말하고 있다. 이는 이미 재고가 많기 때문에 동물 주제의 프린트는 필요치 않다는 뜻이므로 정답은 (C)이다."}], "script": [{"sp": "W", "en": "Hi. It's Sarai. I'm calling about the new wallpaper patterns that your team submitted. We all really like the geometric prints. I'm almost certain that all of those will be approved for production in several different color schemes. And the wallpaper patterns for children's rooms are all so imaginative. You have some truly creative people on your design team. However, the animal-themed prints you sent—the thing is, we have a full supply of those in stock. Call me back so we can discuss it.", "ko": "안녕하세요. 서라이입니다. 귀하의 팀에서 제출하신 새 벽지 패턴과 관련해 전화했습니다. 저희는 모두 기하학적인 프린트가 정말 마음에 들어요. 모두 여러 가지 다양한 색상 조합으로 제작 승인이 될 거라고 거의 확신합니다. 그리고 아이들 방을 위한 벽지 패턴들 모두 아주 상상력이 풍부해 보입니다. 귀하의 디자인 팀에 정말 창의적인 분들이 계시네요. 하지만 보내 주신 동물 주제의 프린트들 말인데요. 문제는, 그런 제품들은 재고가 가득 있습니다. 이 부분을 논의할 수 있도록 제게 다시 전화해 주시기 바랍니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test_05-89-91.mp3", "qs": [{"n": 89, "q": "According to the speaker, what will be opening soon?", "opts": ["A restaurant", "A sports arena", "A performing arts center", "A train station"], "ans": 2, "ko": "화자가 초반부에 내일 밤에 있을 스튜어트 공연 예술 센터의 개장이 폭넓은 관심을 끌고 있다(~ the opening of the Stewart Performing Arts Center tomorrow night has attracted widespread attention)고 했으므로 정답은 (C)이다."}, {"n": 90, "q": "Why did the building's designer win an award?", "opts": ["For using solar power", "For creating a rooftop garden", "For installing a moving light display", "For employing sound-absorbing walls"], "ans": 3, "ko": "화자가 중반부에 디자이너가 건물의 방음벽으로 상을 받았다며, 이 벽이 소리를 흡수하는 고무 소재로 되어 있다(The designer won an award for the building's insulated walls. They have rubber material that absorbs sound ~)고 했으므로 정답은 (D)이다."}, {"n": 91, "q": "What does the speaker emphasize about upcoming events?", "opts": ["Many of them are sold out.", "Some of them will be affected by the weather.", "Public transportation will be free.", "Discounts are available for large groups."], "ans": 0, "ko": "화자가 후반부에 주의하라며, 많은 공연이 이미 매진되었다(We warn you, though—many shows are already sold out!)고 했으므로 정답은 (A)이다."}], "script": [{"sp": "M", "en": "In local news, the opening of the Stewart Performing Arts Center tomorrow night has attracted widespread attention. This state-of-the-art center holds three different theaters. The designer won an award for the building's insulated walls. They have rubber material that absorbs sound from the other theaters and nearby trains. On top of this, the interior decoration is magnificent. If you'd like to see some photos, browse upcoming shows, and plan your visit, go to the theater's Web site. We warn you, though—many shows are already sold out!", "ko": "지역 소식입니다. 내일 밤에 있을 스튜어트 공연 예술 센터의 개장이 폭넓은 관심을 끌고 있습니다. 이 최신식 센터는 세 개의 극장을 보유하고 있습니다. 디자이너는 건물의 방음벽으로 상을 받았습니다. 이 벽은 다른 극장과 근처의 기차에서 나는 소리를 흡수하는 고무 소재로 되어 있습니다. 그뿐만 아니라, 실내 장식도 훌륭합니다. 사진을 보고, 곧 있을 공연도 둘러보시면서, 방문 계획을 세우기를 원하시면, 극장 웹사이트를 방문하세요. 하지만 주의하세요. 많은 공연이 이미 매진되었습니다!"}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test_05-92-94.mp3", "qs": [{"n": 92, "q": "Who is Mona Alamri?", "opts": ["A local official", "A ship captain", "A marine scientist", "An engineer"], "ans": 3, "ko": "모나 알람리는 누구인가?"}, {"n": 93, "q": "What is the focus of today's podcast episode?", "opts": ["Coastal mapping", "Offshore wind farms", "Electric ships", "Bridge construction"], "ans": 2, "ko": "오늘 팟캐스트 방송의 초점은 무엇인가?"}, {"n": 94, "q": "What does the speaker alert the listeners to?", "opts": ["A schedule change", "A volunteer opportunity", "An updated Web site", "A project start date"], "ans": 0, "ko": "화자는 청자들에게 무엇에 대해 주의를 주는가?"}], "script": [{"sp": "W-Am", "en": "Regular listeners of the Going Electric podcast may be familiar with today's guest because she was on the podcast last year. Dr. Mona Alamri is a leading transportation engineer. In today's episode, she'll be talking about electric ships that can operate with zero emissions. These high-speed ships may completely change the way people and goods are moved along the world's coastlines. But, before I welcome Dr. Alamri, please note there is a change to next month's schedule—most notably, I'll be on vacation for three weeks.", "ko": "〈고잉 일렉트릭〉의 애청자들은 오늘 초대 손님이 익숙하실 수도 있는데, 작년에 우리 팟캐스트에 나오셨기 때문입니다. 모나 알람리 박사님은 손꼽히는 교통 공학자입니다. 오늘 방송에서는 배출물이 전혀 없이 운항할 수 있는 전기 선박에 관해 이야기해 주실 예정입니다. 이 고속 선박은 사람과 상품이 세계의 해안선을 따라 수송되는 방식을 완전히 바꿀 수 있습니다. 하지만 알람리 박사님을 환영하기 전에, 다음 달 일정에 변동이 있다는 점에 유의하시기 바랍니다. 가장 주목할 만한 것은, 제가 3주 동안 휴가를 간다는 점입니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "M-Cn", "audio": "Test_05-95-97.mp3", "qs": [{"n": 95, "q": "Where are the listeners?", "opts": ["At a bicycle race", "At a marathon", "At a parade", "At a festival"], "ans": 0, "ko": "청자들은 어디에 있는가?"}, {"n": 96, "q": "What will proceeds from the event support?", "opts": ["Creating an athletic field", "Renovating a city library", "Repairing a bridge", "Building a new playground"], "ans": 2, "ko": "행사 수익금은 무엇을 지원할 것인가?"}, {"n": 97, "q": "Look at the graphic. On which street does the speaker say the listeners can find a beverage stand?", "opts": ["Fifth Street", "Rose Street", "Spring Street", "Dill Street"], "ans": 1, "ko": "시각 정보에 의하면, 화자는 청자들이 어느 거리에서 음료 스탠드를 찾을 수 있다고 말하는가?"}], "script": [{"sp": "M-Cn", "en": "Good morning, everyone, and welcome to the fifteenth annual Summerhaven Bicycle Race. The profits from this year's race will help our town fix the Grant Park footbridge, which is in serious need of maintenance. Please take a look at the map to familiarize yourselves with the route the cyclists will be taking. Remember, there's a beverage stand located between city hall and the art museum, so you can stay hydrated while you watch the race.", "ko": "안녕하세요, 여러분. 제15회 연례 서머헤이븐 자전거 경주 대회에 오신 것을 환영합니다. 올해 경주 대회의 수익금은 우리 시가 그랜트 파크 보행자 전용 다리를 수리하는 데 도움을 줄 예정인데요. 이곳은 관리를 심각하게 필요로 하는 상태입니다. 자전거 선수들이 이용할 경로를 숙지할 수 있도록 지도를 보시기 바랍니다. 기억하세요. 시청과 미술관 사이에 음료 스탠드가 있으므로, 경주를 관람하는 동안 수분을 섭취하실 수 있습니다."}], "gimg": "ets_t5_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "M-Au", "audio": "Test_05-98-100.mp3", "qs": [{"n": 98, "q": "What industry is the mobile app intended for?", "opts": ["Entertainment", "Travel", "Education", "Finance"], "ans": 3, "ko": "모바일 앱은 어떤 업계를 대상으로 하는가?"}, {"n": 99, "q": "Look at the graphic. Which stage of market research will Sarai talk about?", "opts": ["Stage 1", "Stage 2", "Stage 3", "Stage 4"], "ans": 0, "ko": "시각 정보에 의하면, 서라이는 시장 조사의 어느 단계에 관해 이야기할 것인가?"}, {"n": 100, "q": "What will begin next Friday?", "opts": ["A seasonal work schedule", "A business conference", "A construction project", "A contract negotiation"], "ans": 0, "ko": "다음 주 금요일에 무엇이 시작될 것인가?"}], "script": [{"sp": "M-Au", "en": "In today's meeting, we'll discuss where we are in our software development process for Universal Banking. In-depth user research will help us create a better online banking application. Sarai will start by telling us about her research into Universal Banking's target customers. What features do they need in a banking app, and how comfortable are they with technology? But before Sarai begins her presentation, let me remind you that as summer begins next week, so do summer hours. You'll be able to stop working at 2:00 o'clock on Friday afternoons, so we'll be moving our regular meeting to Friday mornings.", "ko": "오늘 회의에서는 유니버설 뱅킹을 위한 소프트웨어 개발 과정에서 우리가 어느 단계에 있는지 논의하겠습니다. 심층적인 이용자 조사는 더 나은 온라인 뱅킹 애플리케이션을 만드는 데 도움이 될 것입니다. 서라이가 유니버설 뱅킹의 목표 고객들에 대해 조사한 것을 이야기하며 시작할 예정입니다. 고객들은 뱅킹 앱에서 어떤 기능을 필요로 하고, 기술 사용에 얼마나 익숙할까요? 하지만 서라이가 발표를 시작하기 전에, 다음 주부터 여름이 시작되면서 서머 타임도 시작된다는 것을 상기시켜 드립니다. 금요일 오후 2시에 업무를 중단할 수 있으므로, 정기 회의를 금요일 오전으로 옮길 것입니다."}], "gimg": "ets_t5_g98.jpg"}]};
